import { Component } from '@angular/core';
import { FormBuilder, FormGroup, Validators } from '@angular/forms';
import { Router } from '@angular/router';
import { AuthService } from '../../../services/auth.service';

@Component({
  selector: 'app-register',
  templateUrl: './register.component.html',
  styleUrls: ['./register.component.css']
})

export class RegisterComponent {
  form: FormGroup;
  error = '';
  loading = false;

  constructor(private fb: FormBuilder, private authService: AuthService, private router: Router) {
    this.form = this.fb.group({
      username: ['', [Validators.required, Validators.minLength(3)]],
      email: ['', [Validators.required, Validators.email]],
      first_name: [''],
      last_name: [''],
      password: ['', [Validators.required, Validators.minLength(6)]],
    });
  }

  submit(): void {
    if (this.form.invalid) return;
    this.loading = true;
    this.error = '';
    this.authService.register(this.form.value).subscribe({
      next: () => this.router.navigate(['/dashboard']),
      error: (err) => {
        this.error = Object.values(err.error || {}).flat().join(' ') || 'Registration failed.';
        this.loading = false;
      }
    });
  }
}
<div class="auth-page">
  <div class="auth-card card">
    <h1>Create Account</h1>
    <p class="text-muted">Join Pantry Helper</p>

    <div class="alert alert-danger" *ngIf="error">{{ error }}</div>

    <form [formGroup]="form" (ngSubmit)="submit()">
      <div class="row-2">
        <div class="form-group">
          <label>First Name</label>
          <input class="form-control" formControlName="first_name" placeholder="First name">
        </div>
        <div class="form-group">
          <label>Last Name</label>
          <input class="form-control" formControlName="last_name" placeholder="Last name">
        </div>
      </div>
      <div class="form-group">
        <label>Username *</label>
        <input class="form-control" formControlName="username" placeholder="Choose a username"
          [class.is-invalid]="form.get('username')?.invalid && form.get('username')?.touched">
        <div class="error-msg" *ngIf="form.get('username')?.errors?.['minlength']">
          Minimum 3 characters
        </div>
      </div>
      <div class="form-group">
        <label>Email *</label>
        <input class="form-control" type="email" formControlName="email" placeholder="user@example.com"
          [class.is-invalid]="form.get('email')?.invalid && form.get('email')?.touched">
      </div>
      <div class="form-group">
        <label>Password *</label>
        <input class="form-control" type="password" formControlName="password" placeholder="At least 6 characters"
          [class.is-invalid]="form.get('password')?.invalid && form.get('password')?.touched">
      </div>
      <button type="submit" class="btn btn-primary btn-full" [disabled]="form.invalid || loading">
        {{ loading ? 'Creating account...' : 'Create Account' }}
      </button>
    </form>

    <p class="auth-footer">
      Already have an account? <a routerLink="/login">Sign in</a>
    </p>
  </div>
</div>
